+func TestPause_CreatesFile(t *testing.T) {
+	tmpDir := t.TempDir()
+
+	if err := Pause(tmpDir, "testing", "test-runner"); err != nil {
+		t.Fatalf("Pause() error = %v", err)
+	}
+
+	pauseFile := GetPauseFile(tmpDir)
+	if _, err := os.Stat(pauseFile); os.IsNotExist(err) {
